INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Scheduling and dispatching$q$, $q$Drag-and-drop calendar for assigning jobs to technicians, with recurring job support for maintenance contracts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Quoting$q$, $q$Branded, itemized quotes customers can review and approve online before work is scheduled.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Invoicing and online payments$q$, $q$Automatic invoice generation from completed jobs, with online card and bank payment collection and payment reminders.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Client hub$q$, $q$Self-serve customer portal for viewing quotes, invoices, appointment requests, and payment history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Route optimization$q$, $q$Suggests efficient driving order between scheduled jobs to reduce windshield time for crews.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Mobile app for technicians$q$, $q$Field app for viewing schedules, updating job status, capturing signatures, and taking payment on-site.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$QuickBooks integration$q$, $q$Two-way sync with QuickBooks Online to keep invoicing and bookkeeping data consistent.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Online booking$q$, $q$Customer-facing booking widget that lets clients request appointments directly into the schedule.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Reporting$q$, $q$Dashboards and reports on job status, revenue, and team performance to track business health.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Marketing add-ons$q$, $q$Optional tools for automated review requests, referral tracking, and email/SMS marketing campaigns.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Purpose-built for home service workflows, from quote to invoice to payment$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Mobile app keeps field technicians and the office in sync in real time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Client hub reduces phone and email back-and-forth over quotes and invoices$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$QuickBooks Online integration simplifies bookkeeping handoff$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Free trial makes it easy to test the platform before committing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Costs can climb quickly once extra users and add-ons are included$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Some automation features (two-way texting, job costing) are gated to higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Less depth for very large or multi-branch operations compared to enterprise platforms$q$, 2);
