INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Not a fit for businesses outside scheduled, on-site home service work$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$What is Jobber used for?$q$, $q$Jobber is field service management software used by home service businesses to schedule jobs, send quotes, dispatch technicians, invoice customers, and collect payments in one system.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$How much does Jobber cost?$q$, $q$Jobber's plans start around $29 to $39 per month depending on billing cycle, with higher tiers for more users and features like two-way texting, job costing, and marketing add-ons.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Does Jobber offer a free plan?$q$, $q$Jobber does not offer a permanent free plan, but it does offer a free trial so businesses can test the platform before subscribing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Does Jobber integrate with QuickBooks?$q$, $q$Yes, Jobber offers a two-way integration with QuickBooks Online to keep invoicing and bookkeeping data in sync.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Is Jobber available on mobile devices?$q$, $q$Yes, Jobber has a mobile app for iOS and Android that field technicians use to view schedules, update jobs, and take payments on-site.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Lawn care and landscaping scheduling$q$, $q$Set up recurring maintenance visits, route crews efficiently between properties, and invoice automatically after each visit.$q$, $q$Landscaping and lawn care businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Residential cleaning operations$q$, $q$Manage recurring cleaning schedules, send clients automated reminders, and let them book or rebook appointments online.$q$, $q$Residential and commercial cleaning companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Plumbing and HVAC dispatch$q$, $q$Quote repair or install jobs, dispatch the nearest available technician, and collect payment on-site once work is complete.$q$, $q$Plumbers, electricians, and HVAC technicians$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Owner-operator professionalization$q$, $q$Give a one- or two-person crew branded quotes, a client portal, and automated invoicing to compete with larger competitors.$q$, $q$Solo operators and small service crews$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Core$q$, $q$From $29/month (annual) or $39/month (monthly)$q$, $q$Monthly or annual$q$, $q$["Quoting, scheduling, and invoicing","Client hub and online payments","Single user","Mobile app access"]$q$::jsonb, 0);
