INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Grow$q$, $q$From $199/month (individual) or $349/month (team, 10 users)$q$, $q$Monthly or annual$q$, $q$["Everything in Connect","Two-way texting","Job costing and reporting","Higher user limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Plus$q$, $q$From $599/month (team, 15 users)$q$, $q$Monthly or annual$q$, $q$["Everything in Grow","Premium support","Advanced automation and AI tools","Highest included user count"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jobber is a cloud-based operations platform built specifically for home service businesses such as landscapers, cleaners, plumbers, electricians, and HVAC technicians. Founded in Edmonton, Canada in 2011, the company has grown into one of the more recognizable names in field service management, competing alongside tools like Housecall Pro and ServiceTitan for the same base of independent contractors and small service companies.$q$, $q$At its core, Jobber replaces the spreadsheets, paper forms, and disconnected apps many service businesses rely on with a single system for scheduling jobs, sending quotes, dispatching crews, invoicing customers, and collecting payment. A companion mobile app lets technicians in the field see their schedule, update job status, capture signatures, and take payment on-site, while the web dashboard gives owners and office staff a real-time view of the business.$q$, $q$Jobber also layers in client-facing tools, including an online client hub where customers can approve quotes, view invoices, and pay online, plus optional add-ons for online booking, automated review requests, and marketing campaigns. The overall positioning is a practical, all-in-one back office for service businesses that would otherwise need to stitch together separate scheduling, invoicing, and accounting tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$who-jobber-is-for$q$, $q$Who Jobber Is For$q$, 2, ARRAY[$q$Jobber is aimed squarely at small to mid-sized home service businesses: lawn care and landscaping crews, residential cleaning companies, plumbers, electricians, HVAC and appliance repair technicians, pest control operators, and similar trades that send workers to customer properties on a recurring or one-off basis. Solo operators just getting off paper and spreadsheets, as well as small teams with a handful of technicians, tend to be the sweet spot.$q$, $q$It also suits owner-operators who need to look more professional to customers without hiring dedicated office staff. Features like branded online quotes, automated appointment reminders, and a self-serve client portal help a two- or three-person crew present the same polish as a larger competitor, which matters in industries where trust and responsiveness drive repeat business and referrals.$q$, $q$Businesses that already do some scheduling and invoicing informally, but are losing track of jobs, missing follow-ups, or getting paid late, are strong candidates. Jobber's built-in reminders, recurring job scheduling, and integrated payments are designed to plug exactly those gaps for owners who want more structure without adopting a heavyweight enterprise system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large or highly complex field service operations with hundreds of technicians, multi-branch operations, or heavy dispatch logistics may find Jobber's feature set thinner than purpose-built enterprise platforms such as ServiceTitan, which offer deeper reporting, franchise management, and call-center tooling. Businesses with those needs often outgrow Jobber's structure over time.$q$, $q$Companies outside the home services space, such as retail, e-commerce, restaurants, or professional services that don't dispatch workers to job sites, generally won't find a fit, since Jobber's workflows are built entirely around scheduled visits, quotes, and on-site work rather than general invoicing or point-of-sale needs.$q$, $q$Extremely price-sensitive solo operators who only need basic invoicing, with no scheduling, dispatching, or client-facing quote workflow, may find cheaper standalone invoicing or accounting tools sufficient, since Jobber's monthly cost and paid add-ons (extra users, marketing tools, an AI receptionist) can add up quickly once a business scales past the base plan.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Jobber's core workflow covers the full job lifecycle: capturing a lead, sending a branded quote for customer approval, scheduling the work on a visual calendar, dispatching it to the right technician, and converting the completed job into an invoice. Recurring job scheduling handles maintenance contracts like lawn care or cleaning routes automatically, and route optimization helps crews plan efficient driving order between appointments.$q$, $q$Payments and accounting integration round out the back office, with in-app invoicing, online card and bank payments, automatic payment reminders, and two-way sync with QuickBooks Online to keep bookkeeping consistent. A client hub gives customers self-serve access to quotes, invoices, appointment requests, and payment history, reducing phone and email back-and-forth for office staff.$q$, $q$On top of the core operational features, Jobber offers a mobile app for field technicians, team chat and job notes, custom forms and checklists for on-site work, GPS tracking of crews, and optional add-ons such as online booking widgets, automated review requests, marketing campaign tools, and an AI-powered receptionist for handling inbound calls and messages.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$the-jobber-experience$q$, $q$The Jobber Experience$q$, 2, ARRAY[$q$Day to day, Jobber is designed around a simple loop: the office or owner schedules and quotes work from the web dashboard, while technicians use the mobile app to see their route, update job status, log notes and photos, and collect payment before leaving the property. This tight loop between office and field is generally regarded as one of Jobber's stronger practical benefits for small teams.$q$, $q$New users typically start with a free trial and onboarding resources (help center articles, webinars, and setup guidance) to configure services, pricing, and team roles before going live. Because pricing and available automations scale with plan tier, many businesses start on a lower tier and upgrade as they add technicians or want deeper automation like two-way texting and job costing.$q$, $q$Overall sentiment from reviewers tends to highlight ease of use, mobile reliability, and the quoting-to-invoicing workflow as strengths, while some point to the cost of add-ons and per-user pricing on team plans as a friction point once a business grows past a small crew. It reads as a solid, no-frills operational backbone rather than a highly customizable enterprise platform.$q$]::text[], 4);
