INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Conditional logic$q$, $q$Show, hide, or route form fields and pages based on prior answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Payment collection$q$, $q$Accept payments and donations directly on forms via Stripe, PayPal, Square, and other processors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Jotform Tables$q$, $q$Spreadsheet-style view for organizing, filtering, and managing form submissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Workflow automation$q$, $q$Set up approval flows and multi-step routing that trigger after a form is submitted.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$E-signature (Jotform Sign)$q$, $q$Collect legally binding electronic signatures on contracts and agreements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$PDF Editor$q$, $q$Automatically convert form submissions into formatted, downloadable PDF documents.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$App Builder$q$, $q$Turn forms and workflows into standalone mobile-friendly apps.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Integrations$q$, $q$Connect to CRMs, email marketing tools, cloud storage, and hundreds of other apps.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Very large template library covers most common use cases out of the box$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Free plan is usable for real, low-volume projects, not just a demo$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$No-code editor is approachable for non-technical users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Broad feature set beyond forms, including e-signatures, PDFs, and simple app building$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Wide range of third-party integrations and native payment processor support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Submission and storage limits on lower tiers can be restrictive for growing teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Pricing can rise quickly when moving to higher-volume plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Some advanced features (HIPAA, white-labeling) are gated behind higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Interface can feel dense once workflows, payments, and conditional logic are combined$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Less suited to developers wanting a minimal, headless forms API$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Is Jotform free to use?$q$, $q$Yes, Jotform offers a free Starter plan with limited forms, submissions, and storage. Paid plans remove those caps and unlock features like HIPAA compliance and white-labeling.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Can Jotform accept payments?$q$, $q$Yes, forms can be connected to payment processors such as Stripe, PayPal, and Square to collect one-time payments, subscriptions, or donations directly through the form.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Does Jotform support HIPAA compliance?$q$, $q$Yes, Jotform offers HIPAA-compliant form options on its Gold and Enterprise plans, which are commonly used by healthcare providers for patient intake forms.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$What is the difference between Jotform Tables and Jotform Workflows?$q$, $q$Jotform Tables organizes and displays submitted data in a spreadsheet-like view, while Jotform Workflows automates what happens after a submission, such as approvals or routing to team members.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Can I use Jotform without any coding experience?$q$, $q$Yes, Jotform is built as a no-code, drag-and-drop platform, so forms, workflows, and simple apps can be created without writing any code.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Lead generation and contact forms$q$, $q$Small businesses and marketers embed Jotform contact and lead-capture forms on websites to collect inquiries and route them into a CRM.$q$, $q$Small businesses and marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Patient intake and healthcare forms$q$, $q$Clinics and healthcare providers use HIPAA-compliant Jotform templates to collect patient information and consent digitally.$q$, $q$Healthcare providers and clinics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Event registration and payments$q$, $q$Event organizers build registration forms that collect attendee details and process payment or ticket purchases in one step.$q$, $q$Event organizers and nonprofits$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$HR and internal approvals$q$, $q$HR teams use Jotform Workflows to route job applications, time-off requests, and internal approvals through multi-step processes.$q$, $q$HR teams and internal operations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Starter$q$, $q$Free$q$, $q$Free forever$q$, $q$["Up to 5 forms","100 monthly submissions","100 MB storage","Jotform branding included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Bronze$q$, $q$From $34/month$q$, $q$Billed annually$q$, $q$["25 forms","1,000 monthly submissions","1 GB storage","No Jotform branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Silver$q$, $q$From $39/month$q$, $q$Billed annually$q$, $q$["50 forms","2,500 monthly submissions","10 GB storage","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Gold$q$, $q$From $99/month$q$, $q$Billed annually$q$, $q$["100 forms","10,000 monthly submissions","100 GB storage","HIPAA compliance available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jotform is an online form builder founded in 2006 by Aytekin Tank that has grown into a broad platform for collecting data, payments, and signatures. What started as a simple drag-and-drop form creator now spans workflow automation, an app builder, a PDF editor, and e-signature tools, all built around the same visual, no-code editor.$q$, $q$The core product lets anyone assemble a form from a library of thousands of templates and hundreds of field types, then publish it as a standalone page, embed it on a website, or share it as a link. Behind the scenes, submissions can trigger notifications, populate spreadsheets, feed into approval workflows, or sync with tools like Google Sheets, Salesforce, and Slack.$q$, $q$Jotform's appeal lies in how far the free plan and no-code editor take non-technical users, from solo freelancers building a contact form to large organizations standardizing intake processes across departments. Paid plans add higher submission and storage limits, HIPAA compliance, white-labeling, and enterprise controls.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$who-jotform-is-for$q$, $q$Who Jotform Is For$q$, 2, ARRAY[$q$Jotform suits small business owners, freelancers, and solopreneurs who need professional-looking forms for leads, bookings, or feedback without hiring a developer. Its free tier and template library make it easy to get a working form live within minutes.$q$, $q$It also fits mid-sized teams in healthcare, education, nonprofits, HR, and event management that rely on structured data collection: patient intake, registration forms, job applications, surveys, and order forms. The HIPAA-compliant Gold and Enterprise tiers make it a common choice for clinics and healthcare-adjacent businesses.$q$, $q$Larger organizations that need centralized form governance, single sign-on, and team-based permissions can use Jotform Enterprise to standardize form creation across departments while keeping IT and compliance requirements satisfied.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Developers who need deep custom logic, complex conditional branching beyond what the visual builder supports, or a headless forms API with minimal overhead may find Jotform's interface more consumer-oriented than lightweight developer-first tools.$q$, $q$Teams with very high submission volumes on a tight budget should scrutinize the tiered submission and storage caps carefully, since costs can climb quickly compared to usage-based or flat-fee alternatives once traffic scales past the mid-tier plans.$q$, $q$Organizations that already have a mature no-code stack (a dedicated survey tool, a CRM with native forms, or a workflow platform) may find Jotform redundant unless they specifically need its template breadth, payment integrations, or PDF/e-signature features.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The drag-and-drop Form Builder is the foundation, offering hundreds of field types, conditional logic, and a large template gallery spanning industries from real estate to event registration. Forms can be themed to match brand colors and fonts without writing CSS.$q$, $q$Jotform Tables organizes submissions in a spreadsheet-like view, while Jotform Workflows automates approval chains and routing after a form is submitted. Payment integrations connect to processors like Stripe, PayPal, and Square, letting forms double as checkout pages or donation forms.$q$, $q$Beyond forms, Jotform includes an App Builder for turning forms into mobile-friendly apps, Jotform Sign for e-signatures and document workflows, and Jotform PDF Editor for turning submissions into formatted PDF documents automatically.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$the-jotform-experience$q$, $q$The Jotform Experience$q$, 2, ARRAY[$q$Getting started with Jotform typically means picking a template or starting from a blank canvas, then dragging fields into place while previewing the form live. The editor is approachable enough that non-technical users can build a working form in one sitting.$q$, $q$Day-to-day use revolves around checking submissions in Jotform Tables, tweaking notification emails, and adjusting conditional logic as needs change. Integrations with email marketing, CRM, and storage tools mean most teams rarely need to export data manually.$q$, $q$The tradeoff for that breadth is a fairly dense settings surface once you move past basic forms — payment setup, HIPAA settings, and workflow automation each have their own configuration screens, so newer users may need to explore the help center before assembling more advanced use cases.$q$]::text[], 4);
