INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Drag-and-drop document builder$q$, $q$Place signature, initial, date, checkbox, and text fields anywhere on an uploaded PDF or Word document, or on a new document built from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$1,000+ signable templates$q$, $q$Ready-made templates for HR, healthcare, real estate, and general business agreements speed up getting a document ready to send.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Multi-party sequential signing$q$, $q$Route a single document through multiple signers in a defined order, so each party signs only after the previous one has completed their fields.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Sign Inbox status tracking$q$, $q$A dedicated inbox shows which documents are pending, signed, or stalled, and triggers automated reminder emails to signers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Audit trail and tamper-evident certificates$q$, $q$Completed documents record timestamps, IP addresses, and signer details to support the document's legal validity.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$PDF and Word import$q$, $q$Convert an existing PDF or Word file into a fillable, signable document in a few clicks instead of rebuilding it from scratch.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Third-party integrations$q$, $q$Connects with Google Sheets, Zapier, Dropbox, Slack, HubSpot, Zoho CRM, monday.com, Stripe, PayPal, and QuickBooks Online.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Mobile signing app$q$, $q$A mobile app lets signers and account owners review, sign, and track documents from a phone or tablet.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$HIPAA-compliant plans$q$, $q$Gold and Enterprise plans add HIPAA compliance for organizations that need to collect signatures on protected health information.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Embeddable signing forms$q$, $q$Signable documents can be embedded directly on a website in addition to being shared by email or direct link.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Free Starter plan lets teams start collecting signatures without any upfront cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Tight integration with Jotform's form builder and Tables for end-to-end data collection plus signing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Large library of industry-specific templates speeds up document setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Paid tiers are generally less expensive than standalone e-signature suites for small teams$q$, 3);
