INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$CRM and contact management$q$, $q$Track leads and customers through the sales pipeline with tagging, segmentation, and activity views.$q$, 6);
