INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Analytics dashboard$q$, $q$Monitor sales, contact growth, and funnel performance from a centralized reporting view.$q$, 9);
