INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$What is Kajabi used for?$q$, $q$Kajabi is used to build, host, and sell online courses, coaching programs, memberships, and other digital products, along with marketing them through built-in email, funnel, and website tools.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Does Kajabi take a percentage of sales?$q$, $q$No, Kajabi charges a flat monthly or annual subscription fee rather than taking a percentage of product sales, though standard payment processor fees still apply.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Is there a free trial for Kajabi?$q$, $q$Kajabi offers a free trial period for new users to test the platform before committing to a paid plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$What is the difference between Kajabi's plans?$q$, $q$Plans mainly differ by the number of products, contacts, admin users, and websites allowed, with higher tiers unlocking more capacity and additional features like extra websites and admin seats.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Can I sell memberships and coaching, not just courses, on Kajabi?$q$, $q$Yes, Kajabi supports multiple product types including self-paced courses, cohort-based coaching programs, and recurring memberships within the same account.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Launching an online course$q$, $q$Creators package their expertise into structured video lessons, quizzes, and downloadable resources, then sell access through a Kajabi-hosted checkout.$q$, $q$Independent course creators and subject-matter experts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Running a paid membership community$q$, $q$Businesses offer ongoing access to exclusive content, community discussion, and recurring updates in exchange for a recurring subscription fee.$q$, $q$Membership site owners and community builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Selling coaching and consulting programs$q$, $q$Coaches use pipelines and scheduling-adjacent tools to sell and deliver one-on-one or group coaching packages alongside supporting content.$q$, $q$Coaches and consultants$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Consolidating a creator's marketing stack$q$, $q$Creators replace separate website, email, and payment tools with a single platform to simplify operations and reduce monthly software costs.$q$, $q$Small creator businesses and solo entrepreneurs$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Basic$q$, $q$$179/month ($143/month billed annually)$q$, $q$Monthly or annual$q$, $q$["1 website","5 products","2,500 contacts","2 admin users","Kajabi AI features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Growth$q$, $q$$249/month ($199/month billed annually)$q$, $q$Monthly or annual$q$, $q$["1 website","50 products","25,000 contacts","11 admin users","Advanced automations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$Pro$q$, $q$$499/month ($399/month billed annually)$q$, $q$Monthly or annual$q$, $q$["3 websites","Unlimited products","100,000 contacts","26 admin users","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kajabi is a cloud-based platform that lets entrepreneurs, coaches, and content creators build and sell online courses, coaching programs, memberships, and digital products without stitching together separate tools for hosting, payments, email, and websites. Founded in 2010 by Kenny Rueter and Travis Rosser in Irvine, California, the company grew out of a simple need to help creators monetize knowledge online, and it has since become one of the most recognized names in the creator economy and online education space.$q$, $q$The platform combines a website builder, course and membership hosting, email and marketing automation, sales funnels, and payment processing into a single subscription, positioning itself as an alternative to running WordPress, a separate LMS, an email service provider, and a payment gateway all at once. Kajabi also layers in built-in analytics, customer relationship tools, and, more recently, AI-assisted content creation features that help users draft course outlines, marketing copy, and email sequences.$q$, $q$Kajabi targets solo creators and small teams rather than large enterprises, charging a flat monthly or annual subscription rather than taking a percentage of sales. Its pricing has shifted over the years, with entry-level plans being adjusted and consolidated, but the core promise remains the same: give non-technical creators the infrastructure to launch and scale a digital product business from one dashboard.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$who-kajabi-is-for$q$, $q$Who Kajabi Is For$q$, 2, ARRAY[$q$Kajabi is built for course creators, coaches, consultants, and membership-site owners who want to package expertise into a paid digital product and sell it directly to an audience. Fitness instructors, business coaches, authors, and subject-matter experts who already have or are building an audience tend to get the most value, since the platform is optimized for turning followers or email subscribers into paying customers.$q$, $q$It also suits creators who want to consolidate their tech stack. Someone currently juggling a separate website host, a course platform, an email marketing tool, and a payment processor can often replace all of them with a single Kajabi subscription, which simplifies billing and reduces the operational overhead of running multiple integrations.$q$, $q$Small teams and agencies that manage several client-facing courses or membership sites also gravitate toward Kajabi's higher-tier plans, which support multiple websites, larger contact lists, and additional admin seats, making it workable for slightly more complex, multi-brand operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Kajabi is less suited to hobbyists or first-time creators testing an idea on a tight budget, since its entry-level pricing sits meaningfully higher than many standalone course or membership tools. Anyone who isn't yet sure their course or coaching offer will sell may find the monthly commitment hard to justify before generating revenue.$q$, $q$Businesses that need deep e-commerce functionality, complex product catalogs, or highly customized storefronts may find Kajabi's built-in store more limited than dedicated e-commerce platforms, and may be better served by pairing a specialized shopping cart with a simpler course tool.$q$, $q$Developers and teams wanting granular control over site code, custom backend logic, or a fully bespoke design system may also outgrow Kajabi's page-builder and templating approach, since it favors guided customization over open-ended development flexibility.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Kajabi provides course and content hosting with support for video, audio, downloadable files, quizzes, and drip-fed lessons, alongside a website and landing page builder with customizable themes so creators can present their brand without hiring a developer. Built-in marketing tools include email broadcasts and automations, sales funnels, and pipeline templates designed to guide visitors from opt-in to purchase.$q$, $q$Kajabi also includes native payment processing and checkout, subscription and payment-plan billing for memberships and courses, and a CRM-style contact and pipeline view that tracks customer behavior across the funnel. Community and membership features let creators host discussion spaces and cohort-based programs alongside self-paced content.$q$, $q$More recently, Kajabi has added AI-assisted tools that help generate course outlines, sales copy, and email content from a short prompt, along with mobile apps that let creators deliver branded course experiences to students on iOS and Android devices.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', $q$kajabi-experience$q$, $q$The Kajabi Experience$q$, 2, ARRAY[$q$Using Kajabi typically starts with a guided setup flow that helps new users pick a product type, whether that's a course, a coaching program, or a membership, and walks through building the first pipeline. The dashboard centralizes products, marketing, and contacts, so most day-to-day work happens without leaving the platform, which is a deliberate contrast to managing several disconnected tools.$q$, $q$The learning curve is generally moderate: the interface favors templates and pre-built pipelines over blank-canvas flexibility, which speeds up launch time but can feel restrictive for users wanting highly custom designs. Kajabi University and its template library aim to offset this by giving less technical users proven starting points rather than requiring them to design from scratch.$q$, $q$Overall, the day-to-day experience is oriented around launching and marketing a product quickly rather than deep technical customization, which matches its target audience of creators who want to spend more time on content and audience-building than on tool maintenance.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
