INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c36767cb-32ab-4d26-8f68-e5a87e160f08', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Blueprints$q$, $q$Reusable bundles of apps, scripts, and configuration profiles that are continuously enforced on any device assigned to them, letting IT define a policy once and apply it across many machines.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Auto Apps$q$, $q$A catalog of common business applications that Kandji packages, hosts, and keeps automatically updated, removing the need for IT to manually maintain installers and patches.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Zero-Touch Deployment$q$, $q$Integration with Apple's Automated Device Enrollment so new Mac and iOS devices configure themselves, install required software, and apply security settings as soon as an employee signs in.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Self Service$q$, $q$An end-user app catalog that lets employees install IT-approved software on demand without filing a help desk ticket.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$One-Click Compliance Templates$q$, $q$Pre-built control sets mapped to frameworks such as SOC 2, HIPAA, ISO 27001, and PCI DSS that can be applied to a Blueprint to speed up audit preparation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Kandji EDR$q$, $q$An endpoint detection and response module that runs on the same lightweight agent as the MDM, monitoring for suspicious file activity and quarantining threats.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Liftoff Custom Onboarding$q$, $q$A branded out-of-box setup experience that guides new users through account creation and initial device configuration during enrollment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Real-Time Device Inventory & Reporting$q$, $q$Live visibility into hardware, software, and compliance status across the fleet, with reporting to track patch levels and policy adherence.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Third-Party Integrations$q$, $q$Connections to identity providers like Okta and Google Workspace and tools such as Slack, SIEM platforms, and ticketing systems, plus an API for scripting Blueprint assignment and reporting.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Purpose-built for Apple hardware, with automations and defaults tuned specifically to macOS and iOS rather than a generic cross-platform MDM$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Modern, relatively easy-to-learn admin console compared with older MDM tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Combines MDM and EDR on a single agent, simplifying the security stack for lean IT teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Pre-built compliance templates can shorten SOC 2 and HIPAA audit preparation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Large library of reusable Blueprints and Auto Apps reduces repetitive manual configuration work$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Pricing is quote-based and not fully transparent, requiring a sales conversation for an exact cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Historically built exclusively around Apple devices, limiting its usefulness for organizations with significant Windows or Android fleets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Per-device costs can add up for larger fleets, especially once EDR or other add-on modules are included$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Some advanced Blueprint logic and automation setup has a learning curve for new admins$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Minimum device commitments can make it a poor fit for very small teams with only a few Apple devices$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$What is Kandji used for?$q$, $q$Kandji is an MDM platform used by IT teams to enroll, configure, secure, and monitor fleets of Mac, iPhone, iPad, and Apple TV devices from a central console.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Does Kandji support Windows or Android devices?$q$, $q$Kandji's core platform was built specifically for Apple's ecosystem (macOS, iOS, iPadOS, and tvOS) rather than as a general cross-platform device manager.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$How much does Kandji cost?$q$, $q$Kandji publishes starting per-device prices (from roughly $1.60/device/month for iOS/iPadOS/tvOS and $3.20/device/month for macOS), but a final quote depends on device count, contract length, and add-ons like EDR.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Is Kandji a good alternative to Jamf?$q$, $q$Yes, Kandji is commonly evaluated as a modern alternative to Jamf for organizations wanting Apple-focused MDM with a newer admin interface and built-in security and compliance tooling.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Can end users install their own apps in Kandji?$q$, $q$Yes, Kandji's Self Service catalog lets end users install IT-approved applications on demand without needing an administrator to push each install manually.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Zero-Touch Onboarding for New Hires$q$, $q$New Mac and iPhone devices are shipped directly to employees and automatically enroll, configure, and install required software the first time the device is powered on.$q$, $q$IT teams onboarding remote or distributed employees$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Apple Fleet Compliance Automation$q$, $q$IT and security teams apply one-click compliance templates to demonstrate controls for frameworks like SOC 2 or HIPAA, reducing manual evidence collection during audits.$q$, $q$Security and compliance teams at growing companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Consolidated MDM and Endpoint Security$q$, $q$Small IT and security teams run device management and endpoint detection and response from a single agent and console instead of stitching together separate MDM and EDR products.$q$, $q$Lean IT teams managing security in-house$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Managed Service Provider Client Deployments$q$, $q$MSPs and IT consultancies build reusable Blueprints and Auto App sets that can be deployed and adapted across multiple Apple-centric client environments.$q$, $q$MSPs and IT consultancies serving Apple-centric clients$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$MDM for iOS, iPadOS & tvOS$q$, $q$From $1.60/device/month$q$, $q$Annual, billed per device$q$, $q$["Automated Device Enrollment","Blueprints & Auto Apps","Self Service app catalog","Compliance templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$MDM for Mac$q$, $q$From $3.20/device/month$q$, $q$Annual, billed per device$q$, $q$["FileVault & security profiles","Blueprints & Auto Apps","Liftoff custom onboarding","Device inventory & reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Kandji EDR Add-On$q$, $q$Custom pricing$q$, $q$Annual, per device add-on$q$, $q$["Endpoint detection & response","Runs on the existing MDM agent","Threat quarantine","Security event reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Enterprise / Custom Bundle$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Volume discounts for large fleets","Bundled MDM, EDR, and compliance modules","Dedicated onboarding & support","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kandji is a cloud-based mobile device management (MDM) platform built specifically for organizations that run on Apple hardware. Since launching in 2018 out of San Diego, it has grown into one of the more prominent modern alternatives to legacy MDM vendor Jamf, marketing itself around a cleaner admin console and a library of pre-built automations for IT teams managing fleets of Mac, iPhone, iPad, and Apple TV devices.$q$, $q$The platform centers on "Blueprints," reusable bundles of apps, scripts, and configuration profiles that continuously enforce a desired state across a group of devices, plus "Auto Apps," a catalog of common business software Kandji pre-packages and keeps patched automatically. Combined with Apple's Automated Device Enrollment, these features let IT teams ship a Mac to a new hire and have it configure itself, install required software, and apply security controls the moment the employee logs in.$q$, $q$Beyond core MDM, Kandji has expanded into endpoint security, running its own Endpoint Detection and Response (EDR) product on the same lightweight agent used for device management, and offering one-click templates that map device controls to frameworks such as SOC 2, HIPAA, ISO 27001, and PCI DSS. That combination of device management, security, and audit-readiness in a single Apple-native tool is the core of its pitch to IT and security teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$who-kandji-is-for$q$, $q$Who Kandji Is For$q$, 2, ARRAY[$q$Kandji is aimed at IT administrators and IT operations teams inside companies that are predominantly or entirely built on Apple hardware, from fast-growing startups to mid-market and larger enterprises. It fits organizations that need to provision dozens to thousands of Mac and iOS devices quickly, consistently, and with minimal manual touch from an IT team that may be small relative to the number of devices it supports.$q$, $q$It is also a strong fit for security- and compliance-conscious teams, especially those pursuing or maintaining SOC 2, HIPAA, or similar certifications, since Kandji's compliance templates and built-in EDR reduce the amount of custom tooling and manual evidence-gathering auditors typically require. Companies onboarding remote or distributed employees particularly benefit from Kandji's zero-touch enrollment process.$q$, $q$Managed service providers and IT consultancies supporting multiple Apple-centric clients also use Kandji, since Blueprints and Auto Apps can be templated and reused across customer environments. Its API and support for scripted, repeatable configuration make it a practical fit for lean teams that would rather standardize a setup once than manage devices individually.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations with predominantly Windows or Android device fleets, or genuinely mixed environments where Apple hardware is only a small slice of the estate, will get less value from Kandji, since its feature set, automation library, and compliance templates were built specifically around Apple's management APIs rather than as a cross-platform solution covering every operating system a company runs.$q$, $q$Very small teams with only a handful of Apple devices may find the pricing and any minimum device commitments harder to justify than a lighter-weight or free MDM option, particularly if they don't need advanced automation, EDR, or compliance mapping and are mainly looking to enforce basic passcode or encryption policies.$q$, $q$Buyers who want fully transparent, self-serve pricing without a sales conversation, or who require on-premises or self-hosted deployment rather than a cloud-hosted admin console, may also be frustrated, since Kandji is sold through a quote-based sales process and delivered as a hosted SaaS product rather than software installed and run in-house.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Kandji's product is Blueprints, a system of reusable configuration bundles that group apps, scripts, and security profiles together and continuously enforce them on any device assigned to that bundle, alongside Auto Apps, a library of common business software Kandji hosts, packages, and keeps updated automatically so IT doesn't have to.$q$, $q$Kandji layers zero-touch deployment on top of Apple's Automated Device Enrollment, plus a Self Service catalog that lets end users install approved apps on demand, one-click compliance templates mapped to frameworks like SOC 2 and HIPAA, and Kandji EDR, an endpoint detection and response product that runs on the same agent as the MDM to flag and quarantine suspicious activity.$q$, $q$Rounding out the platform are real-time device inventory and reporting, integrations with identity providers like Okta and Google Workspace plus tools like Slack and common SIEM or ticketing systems, and an API that lets IT teams script Blueprint assignment, app deployment, and reporting rather than working exclusively through the admin console.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$the-kandji-experience$q$, $q$The Kandji Experience$q$, 2, ARRAY[$q$Day to day, Kandji is administered through a web-based console that most reviewers describe as cleaner and faster to learn than older MDM tools, with Blueprints and Auto Apps designed to get a new IT admin to a working configuration in hours rather than days. New Mac and iPhone enrollment for end users is largely invisible, handled automatically once a device is assigned in Apple Business Manager.$q$, $q$Support is delivered through a dedicated customer success and support team along with in-app resources and searchable documentation, and Kandji maintains an active user community where IT admins share Blueprint recipes and troubleshoot edge cases. Implementation for an existing Apple fleet typically involves an initial audit of current devices and policies before configurations are migrated into Blueprints.$q$, $q$Because pricing and onboarding run through a sales team rather than self-serve signup, the first real interaction most prospective customers have with Kandji is a demo and a quote tailored to their device count and desired modules, which can make it harder to evaluate casually compared to tools with published, click-to-buy plans.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$AI subtitle generator$q$, $q$Automatically transcribes spoken audio and syncs captions to the video timeline, with options to edit text and customize caption styling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Smart Cut$q$, $q$Detects and removes silences, dead air, and filler words from talking-head recordings to speed up rough cuts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$AI background removal$q$, $q$Isolates a subject from its background without a physical green screen, letting users composite footage over new backgrounds.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Multi-format resizer$q$, $q$Reformats a single video into multiple aspect ratios for platforms like Instagram, TikTok, and YouTube in one export.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Real-time collaboration$q$, $q$Shareable project links let team members comment, edit, and review videos together, similar to collaborating on a shared document.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Timeline-based editor$q$, $q$Standard trimming, layering, transitions, and text overlay tools for building a video from uploaded or stock media.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Stock media and templates$q$, $q$A built-in library of stock video, images, music, and pre-built templates for common social and marketing formats.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Video-to-text transcription$q$, $q$Converts uploaded audio or video into an editable text transcript for repurposing or accessibility.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Screen recorder$q$, $q$Captures screen activity directly in the browser for tutorials, demos, or quick recordings without separate software.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Workspace and team management$q$, $q$Organizes projects into shared workspaces with member roles, useful for agencies and marketing teams managing multiple clients or campaigns.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$No software installation required; works entirely in a web browser$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Strong AI tools for subtitles, background removal, and silence trimming that save editing time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Real-time collaboration and easy link-sharing for team and client review$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Simple, approachable interface that's fast to learn for non-professional editors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Templates and one-click resizing make repurposing content across social platforms quick$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Free plan adds a watermark and limits exports to short lengths at lower resolution$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Lacks the depth of professional tools like advanced color grading or multi-track audio mixing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Cloud-based rendering can be slower than local editing for long or high-resolution projects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Subscription cost can add up for teams that need multiple paid seats$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Requires a stable internet connection since there is no full offline editing mode$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Is Kapwing free to use?$q$, $q$Yes, Kapwing offers a free plan, but exports include a watermark and are limited in length and resolution. Removing the watermark and unlocking longer, higher-resolution exports requires a paid Pro or Business plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Does Kapwing work on mobile devices?$q$, $q$Kapwing is primarily a browser-based tool that works on desktop and mobile web browsers, since it runs through the internet rather than as a native installed application.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$How accurate are Kapwing's AI subtitles?$q$, $q$Kapwing's automatic subtitle generator produces generally accurate transcriptions for clear audio, though users typically review and lightly edit the generated captions for names, accents, or background noise before finalizing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Can multiple people edit a Kapwing project at the same time?$q$, $q$Yes, Kapwing supports collaborative editing through shareable project links, allowing team members to comment on, review, and edit the same project similar to a shared document.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$What is the difference between Kapwing's Pro and Business plans?$q$, $q$The Business plan builds on Pro with a higher monthly credit allowance for AI tools like subtitling and background removal, along with expanded usage limits designed for teams producing a larger volume of video content.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Repurposing podcast episodes into social clips$q$, $q$Podcasters upload raw audio or video recordings and use Smart Cut and auto-subtitles to quickly produce short, captioned clips for social media.$q$, $q$Podcasters and audio creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Batch-producing platform-specific social videos$q$, $q$Marketing teams use the resizer and templates to reformat a single video into multiple aspect ratios for Instagram, TikTok, and YouTube.$q$, $q$Social media managers and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Collaborative client video review$q$, $q$Agencies share project links with clients so they can review drafts and leave feedback directly within the editor before final export.$q$, $q$Marketing and creative agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Adding captions for accessibility and silent viewing$q$, $q$Creators and businesses use the AI subtitle generator to add accurate captions to videos, improving accessibility and watchability without sound.$q$, $q$Content creators and small businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Watermarked exports","Exports limited to short video length at 720p","250MB upload limit","Limited project storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Pro$q$, $q$From $16/month (billed annually) or $24/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["No watermark on exports","Exports up to 1080p and longer video lengths","Access to AI tools like subtitles, Smart Cut, and background removal","Larger file upload limit and cloud storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Business$q$, $q$From $50/month (billed annually) or $64/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Pro","Higher monthly AI credit allowance","Expanded subtitle and AI tool usage limits","Built for teams producing higher volumes of video"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kapwing is a web-based video editing platform that runs entirely in the browser, letting anyone create, edit, and export videos without installing desktop software. Founded in 2017 by Julia Enthoven and Eric Lu, the company set out to make video editing as accessible as document editing in Google Docs, with real-time collaboration built into the core experience. Kapwing is headquartered in San Francisco and has grown into one of the more recognizable names among online video tools used by social media managers, marketers, and independent creators.$q$, $q$The platform combines a traditional timeline-based editor with a growing suite of AI-powered utilities, including automatic subtitle generation, background removal, silence trimming, and a Smart Cut tool that can identify and remove filler words or dead air from talking-head footage. Users can resize videos for different platforms, add text and captions, layer audio, and apply templates designed for short-form content like Reels, TikToks, and YouTube Shorts.$q$, $q$Because everything happens in the cloud, projects can be shared with a link the same way a Google Doc is shared, allowing multiple team members to comment, edit, or approve a video without exchanging large files. This collaborative, no-download approach is Kapwing's core differentiator against traditional desktop editors like Premiere Pro or Final Cut Pro, positioning it closer to a lightweight, team-friendly alternative for everyday social and marketing video work rather than a full professional post-production suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$who-kapwing-is-for$q$, $q$Who Kapwing Is For$q$, 2, ARRAY[$q$Kapwing is best suited to social media managers, content marketers, and small teams who need to produce a steady volume of short, polished videos without deep editing expertise. Its browser-based nature means anyone with a laptop and internet connection can jump into a project, which makes it appealing to distributed or remote teams that need to collaborate on video without shared drives or file transfers.$q$, $q$Solo creators, podcasters repurposing audio into video clips, and educators building explainer content also find value in Kapwing's automated subtitle generation and quick trimming tools, which can turn a raw recording into a shareable clip in minutes. Marketing and social teams at small and mid-sized businesses use it to batch-produce platform-specific videos, since built-in templates and aspect-ratio presets for Instagram, TikTok, and YouTube simplify repurposing one piece of content across channels.$q$, $q$Agencies managing multiple client accounts benefit from the workspace and sharing features, which let clients review drafts and leave feedback directly inside the editor rather than through email attachments. Overall, Kapwing fits best for people who value speed, accessibility, and collaboration over frame-by-frame editing precision.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Kapwing is not built for high-end film, broadcast, or complex multi-camera post-production work. Editors who need advanced color grading, precise audio mixing, multi-track compositing, or plugin ecosystems will find the toolset comparatively shallow next to desktop applications like Adobe Premiere Pro, DaVinci Resolve, or Final Cut Pro.$q$, $q$Because Kapwing runs in the browser and renders in the cloud, performance can lag on very long or high-resolution projects, and users working with large raw footage libraries or offline environments may find the upload-and-process workflow slower than a local editing pipeline. Teams with unreliable internet connections or strict data-residency requirements for sensitive footage should also weigh this cloud dependency carefully.$q$, $q$Budget-conscious users who only need occasional, simple edits may find the free plan's watermark, short export length, and file size limits restrictive, and may prefer a one-time-purchase mobile app instead of committing to a recurring subscription. Similarly, users seeking a fully offline, install-once tool with no ongoing cost will likely be better served elsewhere.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Kapwing offers a timeline-based video editor with trimming, layering, transitions, text overlays, and a library of stock media, music, and fonts that can be dropped directly into a project. Its AI-powered subtitle generator automatically transcribes spoken audio and syncs captions to the timeline, which can then be styled and edited manually, a feature especially popular for making social videos accessible and watchable on mute.$q$, $q$Smart Cut analyzes talking-head recordings to detect and remove silences or filler words automatically, speeding up the rough-cut process for podcasters and vloggers. Background removal uses AI to isolate subjects from their backgrounds without a green screen, useful for repositioning speakers over branded backgrounds or other footage. Kapwing also includes a resizer that reformats a single video into multiple aspect ratios for different platforms in one pass, along with templates for common formats like memes, Reels, and YouTube intros.$q$, $q$Collaboration tools sit alongside the editing features: shareable project links, commenting, and multi-user workspaces let teams review and approve videos together in real time. Additional utilities include a video-to-text transcriber, GIF maker, screen recorder, and a set of AI generation tools for scripts and images, rounding out Kapwing's positioning as an all-in-one content studio rather than a single-purpose editor.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$the-kapwing-experience$q$, $q$The Kapwing Experience$q$, 2, ARRAY[$q$Using Kapwing feels closer to working in a cloud productivity app than a traditional editing suite. The interface opens in a browser tab with a familiar timeline at the bottom, a preview window in the center, and tool panels along the sides, so most editing actions are drag-and-drop or a click away rather than buried in nested menus. New users can typically start a basic edit within minutes without a tutorial.$q$, $q$The AI tools are generally the standout part of the day-to-day experience: uploading a clip and generating subtitles or trimming silence with Smart Cut happens with a single click, and results are usually good enough to use with only light manual correction. Rendering and export times depend on video length and current server load, which is the main trade-off users notice compared to local rendering on a desktop machine.$q$, $q$Free-plan users will regularly encounter the export watermark and length limits as a nudge toward upgrading, which can feel restrictive for repeated use but is manageable for occasional edits or testing the platform before committing to a subscription. Overall, the experience emphasizes speed and simplicity for short-form, social-first video production over depth for complex, long-form editing projects.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
