INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$SingleView customer timeline$q$, $q$Combines email, chat, social, and ticket history into one continuous view of each customer's interactions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kay AI agent$q$, $q$An AI agent that can take real actions on tickets, such as refunds, order updates, and password resets, not just draft replies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Shared team inbox$q$, $q$A unified inbox for email, chat, and social messages with collision detection to prevent duplicate agent replies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Live chat widget$q$, $q$Embeddable live chat for real-time conversations that feed directly into the same ticketing and customer view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Self-service knowledge base$q$, $q$A searchable help center that lets customers resolve simple issues without opening a ticket.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Automation and SLA rules$q$, $q$Rule-based routing, prioritization, and service-level tracking to keep tickets moving to the right agent on time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Reporting and analytics$q$, $q$Dashboards covering resolution rates, response times, and agent workload for support managers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Third-party integrations$q$, $q$Connects with tools such as Slack, Stripe, Shopify, Salesforce, HubSpot, Twilio, and Zendesk, plus custom APIs.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Multi-channel ticketing$q$, $q$Consolidates email, chat, and social requests into a single ticketing workflow instead of separate tools.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$SingleView gives agents a genuinely unified history across channels instead of scattered records$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$The Kay AI agent can complete real actions, not just suggest responses, reducing manual work on routine tickets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Pay-per-resolution AI pricing has no seat or setup fees for that component$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Solid range of integrations with commerce, CRM, and communication platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Long-established platform with a mature, purpose-built help desk feature set$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Full Kayako One platform pricing is custom and requires contacting sales rather than transparent self-serve rates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Usage-based AI billing can become harder to predict as ticket volume scales up$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Smaller market presence and brand recognition compared to category leaders like Zendesk or Freshdesk$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Onboarding for the full platform is more sales-assisted than instant self-signup$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Limited publicly documented information on mobile app support compared to larger competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$What is Kayako used for?$q$, $q$Kayako is a help desk platform used by support teams to manage tickets, live chat, and knowledge base content from one unified inbox, with an AI agent that can automatically resolve routine requests.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$How much does Kayako cost?$q$, $q$Kayako's AI agent is billed per resolved ticket starting at $1 per resolution with no seat fees, while the full Kayako One platform is custom-priced based on your team's needs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Does Kayako offer a free trial?$q$, $q$Kayako does not publicly advertise a self-serve free plan; pricing and trial access for the full platform are typically arranged by contacting sales.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$What is SingleView in Kayako?$q$, $q$SingleView is Kayako's feature that combines a customer's email, chat, social, and ticket history into one chronological timeline visible to any agent handling their case.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Does Kayako integrate with other tools?$q$, $q$Yes, Kayako integrates with tools such as Slack, Stripe, Shopify, Salesforce, HubSpot, Twilio, Zendesk, and custom APIs to let its AI agent take action across systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$E-commerce order support$q$, $q$Automatically resolving order status, refund, and shipping questions by connecting the AI agent to Shopify and Stripe.$q$, $q$Online retailers and subscription businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Unified multi-channel support desk$q$, $q$Consolidating email, live chat, and social requests into one shared inbox with full customer history.$q$, $q$Growing support teams managing multiple channels$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$AI-driven ticket deflection$q$, $q$Using the Kay AI agent to resolve repetitive, rules-based tickets before they reach a human agent.$q$, $q$Support operations leaders focused on efficiency$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Account and access management support$q$, $q$Handling password resets, account updates, and similar routine requests automatically via integrations.$q$, $q$SaaS and B2B support teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kay AI Agent (Pay-Per-Resolution)$q$, $q$$1 per resolved ticket$q$, $q$Per resolution$q$, $q$["No seat or setup fees","AI agent completes actions like refunds and order updates","Integrates with Slack, Stripe, Shopify, Salesforce, and more","Billed only when a ticket is fully resolved"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kayako One (Full Platform)$q$, $q$Custom pricing$q$, $q$Custom / contact sales$q$, $q$["Unified shared inbox and ticketing","Knowledge base and live chat widget","Automation rules and SLA tracking","Reporting and analytics","Includes Kay AI agent access"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kayako is a customer support and help desk platform built around a single idea: agents should never have to hunt across tools to understand a customer's history. Its signature SingleView feature stitches together email, live chat, social messages, and past tickets into one continuous timeline, so support staff can pick up a conversation with full context regardless of which channel it started on.$q$, $q$The company has been through several eras since it first launched. What began as a traditional on-premise and cloud ticketing system has evolved into an AI-forward support platform, with the current product centered on Kay, an AI agent that can take real action on tickets, such as issuing refunds, updating orders, or resetting passwords, rather than just suggesting canned replies.$q$, $q$Kayako's newer pricing approach reflects that shift: instead of charging purely per agent seat, it bills per resolved ticket for AI-handled conversations, layered on top of a broader Kayako One platform that includes the inbox, ticketing, knowledge base, and reporting tools support teams expect from a modern help desk.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$who-kayako-is-for$q$, $q$Who Kayako Is For$q$, 2, ARRAY[$q$Kayako suits small to mid-sized support teams that handle a steady volume of repetitive requests, such as order status checks, password resets, or account changes, and want to offload a meaningful share of that volume to automation rather than adding headcount. Teams with a support inbox in the low thousands of tickets per month are a natural fit for its pay-per-resolution model.$q$, $q$It also appeals to companies already using tools like Shopify, Stripe, Salesforce, or Slack, since Kayako is built to plug into those systems so the AI agent can actually complete actions inside them, not just log a ticket about the problem. E-commerce and subscription businesses with well-defined, rules-based support workflows tend to see the clearest value.$q$, $q$Support leaders who want a single customer-history view without juggling separate chat, email, and social tools will also find Kayako's core proposition appealing, since SingleView was designed specifically to eliminate that kind of context-switching for agents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need fully transparent, self-serve pricing before talking to sales may find Kayako frustrating, since the full Kayako One platform is quoted on a custom basis and the headline pay-per-resolution rate only tells part of the cost story once platform and volume fees are added.$q$, $q$Very high-volume support operations should model costs carefully, because usage-based AI billing can scale unpredictably as ticket counts grow, in contrast to a flat per-agent fee that stays constant regardless of volume. Teams with highly unpredictable ticket spikes may prefer a predictable seat-based competitor instead.$q$, $q$Buyers who specifically want a large, well-known incumbent with the broadest possible app-marketplace and community ecosystem, such as Zendesk or Freshdesk, may find Kayako's smaller footprint and company size a drawback if breadth of pre-built integrations and third-party plugins matters more than depth of AI automation.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Kayako is its unified ticketing system, which brings email, live chat, and social conversations into one shared inbox, complete with collision detection so multiple agents don't accidentally respond to the same customer twice. Automation rules and SLA tools sit on top to route and prioritize tickets automatically.$q$, $q$The Kay AI agent extends that foundation by handling routine requests end-to-end, using integrations with commerce, CRM, and communication platforms to actually complete the action a customer asked for, rather than just drafting a reply for a human to send. A self-service knowledge base helps deflect simple questions before they become tickets at all.$q$, $q$Reporting and analytics dashboards let managers track resolution rates, response times, and agent workload, while the SingleView customer timeline remains the connective layer that ties every channel and interaction back to a single, chronological customer record for anyone who picks up the conversation.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$the-kayako-experience$q$, $q$The Kayako Experience$q$, 2, ARRAY[$q$Day to day, agents in Kayako work from a shared inbox that looks familiar to anyone who has used a modern help desk, but with the customer's full history, past purchases, and prior conversations visible alongside the current ticket, reducing the need to ask customers to repeat themselves.$q$, $q$For routine requests, the Kay AI agent often resolves the ticket before a human agent ever sees it, escalating only when a case falls outside its configured actions, which shifts the human team's day toward more complex, judgment-heavy conversations rather than repetitive lookups.$q$, $q$Setup and onboarding for the full platform tends to be a more guided, sales-assisted process than a self-service signup, reflecting Kayako's positioning toward mid-market and growing support teams that want a configured system tailored to their specific channels and integrations rather than a generic out-of-the-box tool.$q$]::text[], 4);
